mapper.select:
SELECT t.id, t.title, t.category_code, t.description, t.location_text, t.volunteer_slots, t.filled_slots, t.priority, t.reward_points, t.status, t.start_time, t.end_time, u.username AS owner FROM neighbor_support_task t LEFT JOIN users u ON t.requester_user_id = u.user_id
t.status = #{status}
ORDER BY t.created_at DESC
